import React, { useEffect, useState } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import { authorize, refresh } from 'react-native-app-auth';
import AsyncStorage from '@react-native-async-storage/async-storage';

const config = {
  issuer: 'https://your-oauth-server.com',
  clientId: 'your_client_id',
  clientSecret: 'your_client_secret', // Store securely
  redirectUrl: 'com.yourapp:/oauth2redirect',
  scopes: ['openid', 'profile', 'email'],
};

const App = () => {
  const [accessToken, setAccessToken] = useState(null);

  const authenticate = async () => {
    try {
      const result = await authorize(config);
      setAccessToken(result.accessToken);
      await AsyncStorage.setItem('refreshToken', result.refreshToken);
    } catch (error) {
      Alert.alert('Authentication Error', error.message);
    }
  };

  const refreshToken = async () => {
    const refreshToken = await AsyncStorage.getItem('refreshToken');
    if (refreshToken) {
      try {
        const newToken = await refresh(config, { refreshToken });
        setAccessToken(newToken.accessToken);
        await AsyncStorage.setItem('refreshToken', newToken.refreshToken);
      } catch (error) {
        Alert.alert('Token Refresh Error', error.message);
      }
    }
  };

  useEffect(() => {
    const interval = setInterval(() => {
      refreshToken();
    }, 3600000); // Refresh token every hour

    return () => clearInterval(interval);
  }, []);

  return (
    <View>
      <Text>{accessToken ? 'Authenticated' : 'Not Authenticated'}</Text>
      <Button title="Login" onPress={authenticate} />
    </View>
  );
};

export default App;